var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장이 고용한 뜨내기라더니……. 확실히 흥미로운 연구 대상이구려.","JPN":"学会長が雇った流れ者だと聞いたが……確かに興味深い研究対象だ。","ENG":"I heard you were some goon hired by the President... But you truly are an interesting subject.","TWN":"聽說你是學會長雇傭的新人……確實是個有趣的研究物件呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"자료로만 봤던 맨션의 암살자도 이 정도 수준일지, 궁금해지는군.","JPN":"資料でした見たことのないマンションの暗殺者もこのくらいのレベルなのか、気になるな。","ENG":"I'm curious if you're on an equal level with the Mansion's Assassin, whom I've only seen in documents.","TWN":"我很好奇，只在資料中看到過的曼森暗殺者，也就這個水準嗎。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"뭐, 수적인 열세에는 어쩔 수 없는 모양이지만.","JPN":"ま、数的な劣勢は仕方ないようだが。","ENG":"However, I guess you can't win being outnumbered.","TWN":"嗯，不過在數量上處於劣勢也是沒辦法的事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아하하, 그 언니는 사람 죽이는 재주가 죽이는 거고……","JPN":"あはは、あのお姉さんは、人を殺す才能がすごいけど……","ENG":"Ahahaha! That girl kills people because she's good at it.","TWN":"哈哈哈，因為那個姊姊殺人的手法一流……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"나는…… 콜록!","JPN":"アタシは……ゲホッ！","ENG":"I, on the other hand– *Cough!*","TWN":"而我……咳咳！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"괴물 죽이는 재주가 기똥찬 편이거든.","JPN":"怪物を殺す才能がすごいんだよね。","ENG":"Kill monsters because I'm damn good at it.","TWN":"則是殺怪物的手法比較棒。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"카운터도 아니면서 내가 손본 융합체들을 상대로 여기까지 버틴 건 칭찬해 주지.","JPN":"カウンターでもないくせに、私が手を加えた融合体を相手に、ここまで耐えたことは褒めてやろう。","ENG":"I must admit. I applaud you for lasting that long to my customized hybriders.","TWN":"明明不是制裁者，居然還能在我改造的融合體手下堅持到現在，這一點值得誇讚。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"너무 걱정 마시오. 사체를 해부해서 그 비결을 낱낱이 밝혀낼 테니.","JPN":"心配しなくてもいい。死体を解剖し、その秘訣を残さず突き止めよう。","ENG":"But don't you worry. I'll dissect your corpse and uncover all your little secrets.","TWN":"別擔心，我會解剖你的屍體，徹底查出這裡面的秘密。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"에엑, 해부대는 싫은데……","JPN":"げっ、解剖台はイヤだな……","ENG":"Eww... I don't like to be dissected...","TWN":"欸欸，我討厭解剖台……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그냥 순순히 털어 놓으면 안 될까?","JPN":"素直に話すのじゃダメ？","ENG":"How about I just tell you instead?","TWN":"我乖乖說出來不行嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"호오, 역시 단순히 미친 척 굴었던 건가.","JPN":"ほう、やはり単に狂人のふりをしていたのか。","ENG":"Ho-oh, so you were just pretending to be insane.","TWN":"哼，果然是在裝瘋賣傻嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"말할 기회는 주지. 그 범상치 않은 재주의 기원이 무엇이오?","JPN":"話す機会は与えてやろう。そのただならぬ才能の起源は何だ？","ENG":"Very well. I'll give you a chance to speak. So what is the secret to your unusual talent?","TWN":"我給你機會說出來。你那吧尋常的本領是怎麼來的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"때는 1950년 언저리!","JPN":"時は1950年くらい！","ENG":"It all began around in 1950!","TWN":"大概是1950年吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"20세기라고? 연단술에 손을 대기라도 한 건가?","JPN":"20世紀だと？　錬丹術にでも手を出したのか？","ENG":"The 20th century? Are you saying you were involved in alchemy?!","TWN":"20世紀？你是碰了煉丹術嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아니. 난 동료들과 함께 지구 정복을 위해 정찰하러 왔었어.","JPN":"ううん。アタシは仲間と一緒に、地球を征服するために偵察に来たんだよ。","ENG":"No. But my friends and I did come to scout earth before a conquest.","TWN":"不是，為了征服地球，我跟同伴們一起來地球偵察。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"미개한 인간들을 보면서 농담 따먹기를 하는 중이었지.","JPN":"未開の人間たちを見ながら冗談言ってた途中だったんだ。","ENG":"So we were basically joking around while watching humans do their thing.","TWN":"看著未開化的人類，我正在和他們開玩笑。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"헤이, 친구! 내 광선총 한 발이면 모조리 해치우고도 남겠는데?","JPN":"ヘイ、フレンド！　アタシの光線銃一発あれば全部殺せそうだね！","ENG":"\\"Hey! I think a blast of my laser gun will destroy them to bits, no?\\"","TWN":"嘿，朋友！我一槍就能把他們全都幹掉吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"……뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};